import { useState } from "react";
import "./SignatureVerification.css";

const SIG_QUEUE = [
  { id: "SIG-4401", doc: "CHQ-2041", bank: "YES Bank",   payee: "Vikram Enterprises",  conf: 42, status: "rejected",  risk: "HIGH" },
  { id: "SIG-4400", doc: "CHQ-2039", bank: "SBI",        payee: "Priya Sharma",        conf: 73, status: "review",    risk: "MED"  },
  { id: "SIG-4399", doc: "CHQ-2038", bank: "Axis Bank",  payee: "Global Tech Pvt Ltd", conf: 31, status: "rejected",  risk: "HIGH" },
  { id: "SIG-4398", doc: "CHQ-2037", bank: "HDFC Bank",  payee: "Rohan Mehta",         conf: 94, status: "approved",  risk: "LOW"  },
  { id: "SIG-4397", doc: "CHQ-2036", bank: "Kotak Bank", payee: "Alpha Corp",          conf: 88, status: "approved",  risk: "LOW"  },
];

function SigCanvas({ label, color, type }) {
  // SVG mock signature paths
  const paths = {
    reference: "M 30 70 C 50 30, 70 20, 90 50 C 110 70, 130 40, 150 55 C 170 65, 180 50, 200 60",
    test_match: "M 32 68 C 51 31, 71 21, 91 50 C 111 70, 131 40, 151 54 C 170 64, 181 51, 201 60",
    test_forge: "M 30 70 C 45 40, 80 15, 100 50 C 118 70, 145 35, 158 55 C 178 62, 192 45, 210 58",
  };
  return (
    <div className="sig-canvas-wrap">
      <div className="sig-canvas-label">{label}</div>
      <div className="sig-canvas">
        <svg viewBox="0 0 240 100" width="100%" height="100%">
          <path
            d={paths[type] || paths.reference}
            fill="none"
            stroke={color}
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            opacity="0.9"
          />
          {/* second stroke variation */}
          <path
            d={paths[type] ? paths[type].replace(/C (\d+)/g, (m, n) => `C ${+n + 3}`) : paths.reference}
            fill="none"
            stroke={color}
            strokeWidth="1"
            strokeLinecap="round"
            opacity="0.3"
          />
        </svg>
        <div className="sig-canvas-grid" />
      </div>
    </div>
  );
}

function ConfidenceGauge({ value }) {
  const color = value >= 80 ? "var(--accent-green)" : value >= 60 ? "var(--accent-amber)" : "var(--accent-red)";
  const label = value >= 80 ? "GENUINE" : value >= 60 ? "UNCERTAIN" : "FORGED";

  return (
    <div className="conf-gauge">
      <div className="conf-gauge-track">
        <div className="conf-gauge-fill" style={{ width: `${value}%`, background: color }} />
        <div className="conf-gauge-needle" style={{ left: `${value}%`, borderTopColor: color }} />
      </div>
      <div className="conf-gauge-labels">
        <span style={{ color: "var(--accent-red)" }}>FORGED</span>
        <span style={{ color: "var(--accent-amber)" }}>UNCERTAIN</span>
        <span style={{ color: "var(--accent-green)" }}>GENUINE</span>
      </div>
      <div className="conf-gauge-result" style={{ color }}>
        <span className="mono" style={{ fontSize: 36, fontWeight: 700 }}>{value}%</span>
        <span style={{ fontSize: 13, letterSpacing: "0.12em", fontFamily: "var(--font-display)", fontWeight: 700 }}>{label}</span>
      </div>
    </div>
  );
}

export default function SignatureVerification() {
  const [selected, setSelected] = useState(SIG_QUEUE[0]);

  const isForged  = selected.conf < 60;
  const sigType   = selected.conf >= 80 ? "test_match" : "test_forge";
  const confColor = selected.conf >= 80 ? "var(--accent-cyan)" : selected.conf >= 60 ? "var(--accent-amber)" : "var(--accent-red)";

  return (
    <div className="sig-page">
      {/* Queue */}
      <div className="sig-queue-panel">
        <div style={{ padding: "16px 20px", borderBottom: "1px solid var(--border-subtle)" }}>
          <span className="card-title">Verification Queue</span>
        </div>
        <div className="sig-list">
          {SIG_QUEUE.map(item => (
            <div
              key={item.id}
              className={`sig-list-item ${selected?.id === item.id ? "selected" : ""}`}
              onClick={() => setSelected(item)}
            >
              <div className="sli-top">
                <span className="mono sli-id">{item.id}</span>
                <span className={`badge ${
                  item.status === "approved" ? "badge-green" :
                  item.status === "rejected" ? "badge-red" : "badge-amber"
                }`}>{item.conf}%</span>
              </div>
              <div className="sli-sub">{item.payee}</div>
              <div className="sli-bank">{item.bank} · {item.doc}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Detail */}
      <div className="sig-detail">
        {/* Sig comparison */}
        <div className="card animate-in">
          <div className="card-header">
            <span className="card-title">Siamese Network — Signature Comparison</span>
            <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
              <span className="badge badge-purple">Model v2.1</span>
              <span className={`badge ${isForged ? "badge-red" : "badge-green"}`}>
                {isForged ? "FORGERY DETECTED" : "SIGNATURE MATCH"}
              </span>
            </div>
          </div>

          <div className="sig-compare-grid">
            <SigCanvas label="Reference Signature (on file)" color="var(--accent-cyan)"   type="reference" />
            <div className="sig-vs">
              <div className="vs-circle">VS</div>
              <div className="vs-arrow">→</div>
            </div>
            <SigCanvas label="Submitted Signature (test)" color={confColor} type={sigType} />
          </div>

          <div className="divider" />

          <ConfidenceGauge value={selected.conf} />
        </div>

        {/* Feature analysis */}
        <div className="sig-analysis-row animate-in animate-in-delay-1">
          <div className="card">
            <div className="card-header"><span className="card-title">Feature Distances</span></div>
            <div className="feature-list">
              {[
                { feat: "Stroke curvature",    dist: isForged ? 0.71 : 0.08, ok: !isForged },
                { feat: "Pressure map",         dist: isForged ? 0.53 : 0.12, ok: !isForged },
                { feat: "Aspect ratio",         dist: isForged ? 0.21 : 0.04, ok: true },
                { feat: "Slant angle",          dist: isForged ? 0.63 : 0.09, ok: !isForged },
                { feat: "Loop formation",       dist: isForged ? 0.45 : 0.07, ok: !isForged },
                { feat: "Endpoint similarity",  dist: isForged ? 0.38 : 0.11, ok: true },
              ].map(f => (
                <div key={f.feat} className="feature-row">
                  <span className="feature-name">{f.feat}</span>
                  <div className="progress-bar" style={{ flex: 1 }}>
                    <div className="progress-fill"
                      style={{
                        width: `${f.dist * 100}%`,
                        background: f.dist > 0.4 ? "var(--accent-red)" : f.dist > 0.2 ? "var(--accent-amber)" : "var(--accent-green)"
                      }}
                    />
                  </div>
                  <span className="mono feature-dist" style={{ color: f.dist > 0.4 ? "var(--accent-red)" : f.dist > 0.2 ? "var(--accent-amber)" : "var(--accent-green)" }}>
                    {f.dist.toFixed(2)}
                  </span>
                </div>
              ))}
            </div>
            <div className="divider" />
            <div style={{ fontSize: 11, color: "var(--text-tertiary)" }}>
              Distance threshold: 0.35 · Lower = more similar
            </div>
          </div>

          <div className="card">
            <div className="card-header"><span className="card-title">Document Context</span></div>
            <div className="meta-list">
              {[
                ["Verification ID",   selected.id],
                ["Linked Document",   selected.doc],
                ["Account Holder",    selected.payee],
                ["Issuing Bank",      selected.bank],
                ["Reference on file", "YES — 3 samples"],
                ["Model Threshold",   "≥ 80% Approve"],
              ].map(([k, v]) => (
                <div key={k} className="meta-row">
                  <span className="meta-key">{k}</span>
                  <span className="meta-val mono">{v}</span>
                </div>
              ))}
            </div>
            <div className="divider" />
            {/* Actions */}
            <div className="sig-actions">
              {selected.conf >= 80 ? (
                <button className="btn btn-primary btn-sm">✓ Confirm Genuine</button>
              ) : (
                <button className="btn btn-danger btn-sm">✕ Flag as Forgery</button>
              )}
              <button className="btn btn-ghost btn-sm">Override Decision</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
